        O
      </div>
      <div>
        <h1 class="text-[16px] font-medium leading-none text-[#1f1f1f]">Project Ollie</h1>
        <p class="text-[11px] text-[#5f6368] mt-1" id="workspace-sub">Baseline Workflow & Agent Delegation</p>
      </div>
    </div>

    <!-- Live Sync status and Active Workspace indicator -->
    <div class="flex items-center gap-3">
      <div id="sync-badge" class="hidden items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-[#e6f4ea] text-[#137333]">
        <span class="w-2 h-2 rounded-full bg-[#137333] animate-pulse"></span>
        Multiplayer Live
      </div>
      <div id="offline-badge" class="flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-[#f0f4f9] text-[#5f6368] border border-[#e3e3e3]">
        <span class="w-2 h-2 rounded-full bg-[#5f6368]"></span>
        Local Storage Mode
      </div>

      <button onclick="openTaskModal()" class="bg-[#0b57d0] hover:bg-[#0842a0] text-white text-[13px] font-medium px-4 py-2 rounded-full shadow-sm transition-colors flex items-center gap-1">
        <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M12 4v16m8-8H4"></path></svg>
        New Task
      </button>
    </div>
  </header>

  <!-- FILTER & CONTROL BAR -->
  <section class="bg-white px-[var(--gemini-side-panel-padding-left)] py-2.5 border-b border-[#e3e3e3] flex flex-wrap items-center justify-between gap-3 flex-shrink-0">
    <div class="flex items-center flex-wrap gap-2.5">
      <!-- Search -->
      <div class="relative">
        <span class="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-[#747775]">
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </span>
        <input type="text" id="search-input" oninput="applyFilters()" placeholder="Search tasks..." class="pl-9 pr-3 py-1.5 w-56 text-[13px] rounded-lg border border-[#747775] focus:outline-none focus:border-[#0b57d0] focus:ring-1 focus:ring-[#0b57d0] bg-white">
      </div>

      <!-- Assignee Filter -->
      <select id="filter-assignee" onchange="applyFilters()" class="text-[13px] px-2.5 py-1.5 rounded-lg border border-[#747775] bg-white text-gray-700 focus:outline-none focus:border-[#0b57d0]">
        <option value="all">All Assignees</option>
        <!-- Options injected dynamically -->
      </select>

      <!-- Track Filter -->
      <select id="filter-track" onchange="applyFilters()" class="text-[13px] px-2.5 py-1.5 rounded-lg border border-[#747775] bg-white text-gray-700 focus:outline-none focus:border-[#0b57d0]">
        <option value="all">All Tracks</option>
        <option value="Eng">Eng</option>
        <option value="UXR">UXR</option>
        <option value="Design">Design</option>
        <option value="Quality">Quality</option>
        <option value="Security">Security</option>
        <option value="Product">Product</option>
      </select>

      <!-- Priority Filter -->
      <select id="filter-priority" onchange="applyFilters()" class="text-[13px] px-2.5 py-1.5 rounded-lg border border-[#747775] bg-white text-gray-700 focus:outline-none focus:border-[#0b57d0]">
        <option value="all">All Priorities</option>
        <option value="High">High</option>
        <option value="Medium">Medium</option>
        <option value="Low">Low</option>
      </select>
    </div>

    <!-- Active User Count / Info -->
    <div class="text-[12px] text-gray-500 font-medium" id="team-info">
      Project Ollie Sync Group • 12 Active Members
    </div>
  </section>

  <!-- KANBAN BOARD CANVAS -->
  <main class="flex-1 overflow-x-auto p-4 flex gap-4 select-none">

    <!-- TO DO COLUMN -->
    <div class="kanban-column flex-1 min-w-[280px] max-w-[360px] flex flex-col h-full" data-status="todo" ondragover="allowDrop(event)" ondrop="drop(event, 'todo')">
      <div class="p-3 pb-2 flex items-center justify-between border-b border-[#e3e3e3] mb-2 flex-shrink-0">
        <div class="flex items-center gap-2">
          <span class="w-2.5 h-2.5 rounded-full bg-gray-400"></span>
          <h3 class="text-[14px] font-medium text-[#1f1f1f]">To Do</h3>
        </div>
        <span id="count-todo" class="text-xs bg-gray-200 text-gray-600 px-2 py-0.5 rounded-full font-medium">0</span>
      </div>
      <div id="tasks-todo" class="flex-1 overflow-y-auto px-2 pb-4 space-y-2">
        <!-- Task Cards Dynamic -->
      </div>
    </div>

    <!-- IN PROGRESS COLUMN -->
    <div class="kanban-column flex-1 min-w-[280px] max-w-[360px] flex flex-col h-full" data-status="progress" ondragover="allowDrop(event)" ondrop="drop(event, 'progress')">
      <div class="p-3 pb-2 flex items-center justify-between border-b border-[#e3e3e3] mb-2 flex-shrink-0">
        <div class="flex items-center gap-2">
          <span class="w-2.5 h-2.5 rounded-full bg-[#0b57d0]"></span>
          <h3 class="text-[14px] font-medium text-[#1f1f1f]">In Progress</h3>
        </div>
        <span id="count-progress" class="text-xs bg-[#d3e3fd] text-[#0b57d0] px-2 py-0.5 rounded-full font-medium">0</span>
      </div>
      <div id="tasks-progress" class="flex-1 overflow-y-auto px-2 pb-4 space-y-2">
