    <!-- IN REVIEW COLUMN -->
    <div class="kanban-column flex-1 min-w-[280px] max-w-[360px] flex flex-col h-full" data-status="review" ondragover="allowDrop(event)" ondrop="drop(event, 'review')">
      <div class="p-3 pb-2 flex items-center justify-between border-b border-[#e3e3e3] mb-2 flex-shrink-0">
        <div class="flex items-center gap-2">
          <span class="w-2.5 h-2.5 rounded-full bg-[#e37405]"></span>
