    ];

    // In-memory application state
    let state = {
      tasks: []
    };

    // Track active drag state
    let draggedTaskId = null;

    // Cache local state string to prevent unwanted UI redraw flashes if no changes happen during polling
    let lastStateHash = "";

    // Initialization
    window.addEventListener('DOMContentLoaded', () => {
      // Set Workspace Title
      if (window.__sandboxWorkspaceName) {
        document.getElementById('workspace-sub').textContent = `Syncing inside ${window.__sandboxWorkspaceName}`;
