      // Render Dropdowns
      populateDropdowns();

      // Load initial state
      loadState();
    });

    // Populate Select elements with Team members list
    function populateDropdowns() {
      const filterAssignee = document.getElementById('filter-assignee');
      const inputAssignee = document.getElementById('task-input-assignee');

      // Clear
      filterAssignee.innerHTML = '<option value="all">All Assignees</option>';
      inputAssignee.innerHTML = '<option value="">Unassigned</option>';

      teamMembers.forEach(m => {
        filterAssignee.innerHTML += `<option value="${m.id}">${m.name}</option>`;
        inputAssignee.innerHTML += `<option value="${m.id}">${m.name} (${m.role})</option>`;
      });
    }

    // Load initial state either from cloud synchronization or fallback localstorage / seed data
    async function loadState() {
      if (envId) {
        // Show Live sync status badge
        document.getElementById('sync-badge').classList.remove('hidden');
        document.getElementById('sync-badge').classList.add('flex');
        document.getElementById('offline-badge').classList.add('hidden');

        await loadSyncedState();
        // Set short poll interval
        setInterval(loadSyncedState, 2000);
      } else {
        // Fallback localstorage
        const localData = localStorage.getItem(syncKey);
        if (localData) {
          state = JSON.parse(localData);
        } else {
          state.tasks = [...seedTasks];
          saveLocalFallback();
        }
        renderBoard();
      }
    }

    // Fetch synchronized multiplayer state from API
    async function loadSyncedState() {
      if (!envId) return;
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();

        if (json.data) {
          const newStateStr = JSON.stringify(json.data);
          // Only re-render if state has actually changed and there are no active edits or modals open
          if (newStateStr !== lastStateHash && !isEditingActive()) {
            state = json.data;
            lastStateHash = newStateStr;
            renderBoard();
          }
        } else {
          // Sync empty, initialize it with seed data
          state.tasks = [...seedTasks];
          await saveSyncedState(state);
          renderBoard();
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    // Push synced state to server
    async function saveSyncedState(newState) {
      if (!envId) return;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
        lastStateHash = JSON.stringify(newState);
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }

    // Save fallback state locally if offline
    function saveLocalFallback() {
      localStorage.setItem(syncKey, JSON.stringify(state));
    }

    // Determine if user is typing or modal is active (to avoid jarring cursor refresh)
    function isEditingActive() {
      const activeEl = document.activeElement;
      const modalOpen = !document.getElementById('task-modal').classList.contains('hidden');
      const isTyping = activeEl && (activeEl.tagName === 'INPUT' || activeEl.tagName === 'TEXTAREA' || activeEl.tagName === 'SELECT');
      return modalOpen || isTyping;
    }

    // Filter rules
    function applyFilters() {
      renderBoard();
    }

    // Main render pipeline
    function renderBoard() {
      const query = document.getElementById('search-input').value.toLowerCase().trim();
      const filterAssignee = document.getElementById('filter-assignee').value;
      const filterTrack = document.getElementById('filter-track').value;
      const filterPriority = document.getElementById('filter-priority').value;

      // Clear all task lists
      const columns = {
        todo: document.getElementById('tasks-todo'),
        progress: document.getElementById('tasks-progress'),
        review: document.getElementById('tasks-review'),
        done: document.getElementById('tasks-done')
      };

      Object.values(columns).forEach(col => col.innerHTML = '');

      // Track task counts
      const counts = { todo: 0, progress: 0, review: 0, done: 0 };

      // Render cards
      state.tasks.forEach(task => {
        // Apply filters
        const matchesSearch = task.title.toLowerCase().includes(query) || (task.description && task.description.toLowerCase().includes(query));
        const matchesAssignee = filterAssignee === 'all' || task.assignee === filterAssignee;
        const matchesTrack = filterTrack === 'all' || task.track === filterTrack;
        const matchesPriority = filterPriority === 'all' || task.priority === filterPriority;

        if (matchesSearch && matchesAssignee && matchesTrack && matchesPriority) {
          counts[task.status]++;

          // Construct UI Card
          const cardHtml = createTaskCardHtml(task);
          if (columns[task.status]) {
            columns[task.status].innerHTML += cardHtml;
          }
        }
      });

      // Update column headers
      document.getElementById('count-todo').textContent = counts.todo;
      document.getElementById('count-progress').textContent = counts.progress;
      document.getElementById('count-review').textContent = counts.review;
      document.getElementById('count-done').textContent = counts.done;
    }

    // Generate individual task card HTML safely
    function createTaskCardHtml(task) {
      const member = teamMembers.find(m => m.id === task.assignee) || { name: 'Unassigned', id: '?', avatarColor: '#747775' };

      // Track tag styles
      const trackBadgeStyles = {
        Eng: 'bg-[#d3e3fd] text-[#0b57d0]',
        UXR: 'bg-[#f3e8ff] text-[#6b21a8]',
        Design: 'bg-[#fef3c7] text-[#92400e]',
        Quality: 'bg-[#fee2e2] text-[#991b1b]',
        Security: 'bg-[#e0f2fe] text-[#0369a1]',
        Product: 'bg-[#e2e8f0] text-[#334155]'
      }[task.track] || 'bg-gray-100 text-gray-700';

      // Priority indicators
      const priorityLabel = {
        High: '<span class="text-xs font-semibold text-red-600 flex items-center gap-1"><span class="w-1.5 h-1.5 rounded-full bg-red-600"></span>High</span>',
        Medium: '<span class="text-xs font-semibold text-amber-600 flex items-center gap-1"><span class="w-1.5 h-1.5 rounded-full bg-amber-500"></span>Med</span>',
        Low: '<span class="text-xs font-semibold text-emerald-600 flex items-center gap-1"><span class="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>Low</span>'
      }[task.priority] || '';

      return `
        <div id="${task.id}" class="task-card p-3.5 select-none cursor-grab active:cursor-grabbing relative" draggable="true" ondragstart="drag(event)" ondragend="dragEnd(event)">
          <div class="flex justify-between items-start gap-2">
