            <h4 class="text-[13.5px] font-medium leading-tight text-gray-900 google-sans hover:text-[#0b57d0] transition-colors cursor-pointer" onclick="editTask('${task.id}')">${escapeHtml(task.title)}</h4>

            <!-- Quick Actions -->
            <div class="flex items-center gap-1.5 flex-shrink-0">
              <button onclick="editTask('${task.id}')" title="Edit Task" class="p-1 text-gray-400 hover:text-[#0b57d0] hover:bg-gray-100 rounded transition-all">
                <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
              </button>
              <button onclick="deleteTask('${task.id}')" title="Delete Task" class="p-1 text-gray-400 hover:text-red-600 hover:bg-gray-100 rounded transition-all">
                <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
              </button>
            </div>
          </div>

          <!-- Description -->
          <p class="text-[12px] text-gray-600 mt-1.5 leading-snug line-clamp-3">${escapeHtml(task.description || '')}</p>

          <!-- Card Footer Metrics/Meta -->
          <div class="mt-4 flex items-center justify-between">
            <div class="flex items-center gap-2">
              <span class="px-2 py-0.5 text-[10.5px] font-medium rounded-full ${trackBadgeStyles}">${task.track}</span>
              ${priorityLabel}
            </div>

            <!-- Member Avatar -->
            <div class="flex items-center gap-1.5" title="${member.name}">
              <span class="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold text-white shadow-sm" style="background-color: ${member.avatarColor}">
                ${member.id}
              </span>
            </div>
          </div>
        </div>
      `;
    }

    // HTML sanitizer
    function escapeHtml(str) {
      if (!str) return '';
      return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
    }

    // HTML5 Drag and Drop API Helpers
    function drag(ev) {
      draggedTaskId = ev.currentTarget.id;
      ev.currentTarget.classList.add('dragging');
      ev.dataTransfer.setData("text/plain", draggedTaskId);
    }

    function dragEnd(ev) {
      ev.currentTarget.classList.remove('dragging');
    }

    function allowDrop(ev) {
      ev.preventDefault();
    }

    function drop(ev, columnStatus) {
      ev.preventDefault();
      const id = ev.dataTransfer.getData("text/plain");
      if (id) {
        moveTask(id, columnStatus);
      }
    }

    // Update state when moving cards
    async function moveTask(id, newStatus) {
      const taskIndex = state.tasks.findIndex(t => t.id === id);
      if (taskIndex > -1 && state.tasks[taskIndex].status !== newStatus) {
        state.tasks[taskIndex].status = newStatus;
        renderBoard();

        // Sync/Save
        if (envId) {
          await saveSyncedState(state);
        } else {
          saveLocalFallback();
        }
      }
    }

    // Open Add/Edit Modal
    function openTaskModal(taskId = null) {
      const modal = document.getElementById('task-modal');
      const form = document.getElementById('task-form');
      form.reset();

      if (taskId) {
        // Edit Mode
        const task = state.tasks.find(t => t.id === taskId);
        if (task) {
          document.getElementById('modal-title').textContent = "Edit Task";
          document.getElementById('task-id').value = task.id;
          document.getElementById('task-input-title').value = task.title;
          document.getElementById('task-input-description').value = task.description || '';
          document.getElementById('task-input-assignee').value = task.assignee || '';
          document.getElementById('task-input-track').value = task.track || 'Eng';
          document.getElementById('task-input-priority').value = task.priority || 'Medium';
          document.getElementById('task-input-status').value = task.status;
        }
      } else {
        // Add Mode
        document.getElementById('modal-title').textContent = "Add New Task";
        document.getElementById('task-id').value = "";
        document.getElementById('task-input-status').value = "todo";
      }

      modal.classList.remove('hidden');
    }

    // Close Modal
    function closeTaskModal() {
      document.getElementById('task-modal').classList.add('hidden');
    }

    // Handle Form Submit
    async function saveTaskForm(event) {
      event.preventDefault();

      const id = document.getElementById('task-id').value;
      const title = document.getElementById('task-input-title').value.trim();
      const description = document.getElementById('task-input-description').value.trim();
      const assignee = document.getElementById('task-input-assignee').value;
      const track = document.getElementById('task-input-track').value;
      const priority = document.getElementById('task-input-priority').value;
      const status = document.getElementById('task-input-status').value;

      if (!title) return;

      if (id) {
        // Update task
        const taskIndex = state.tasks.findIndex(t => t.id === id);
        if (taskIndex > -1) {
          state.tasks[taskIndex] = { ...state.tasks[taskIndex], title, description, assignee, track, priority, status };
        }
      } else {
        // Create task
        const newTask = {
          id: 'task-' + Date.now(),
          title,
          description,
          assignee,
          track,
          priority,
          status
        };
        state.tasks.push(newTask);
      }

      closeTaskModal();
      renderBoard();

      // Sync/Save
      if (envId) {
        await saveSyncedState(state);
      } else {
        saveLocalFallback();
      }
    }

    // Trigger Edit
    function editTask(id) {
      openTaskModal(id);
    }

    // Handle Delete Action
    async function deleteTask(id) {
      if (confirm("Are you sure you want to delete this task?")) {
        state.tasks = state.tasks.filter(t => t.id !== id);
        renderBoard();

        // Sync/Save
        if (envId) {
          await saveSyncedState(state);
        } else {
          saveLocalFallback();
        }
      }
    }
  </script>
